```c
#include <stdio.h>
#include <string.h>

int main() {
    char str[200];
    int freq[256] = {0};  // for all ASCII characters

    printf("Enter a string: ");
    fgets(str, sizeof(str), stdin);
    str[strcspn(str, "\n")] = '\0';

    for(int i = 0; str[i] != '\0'; i++) {
        freq[(unsigned char)str[i]]++;
    }

    printf("\nCharacter frequencies:\n");
    for(int i = 0; i < 256; i++) {
        if(freq[i] > 0) {
            printf("'%c' : %d\n", i, freq[i]);
        }
    }
    return 0;
}
```

```c
#include <stdio.h>

int main() {
    int a[10][10], b[10][10], product[10][10] = {0};
    int r1, c1, r2, c2;

    printf("Enter rows and columns of first matrix: ");
    scanf("%d %d", &r1, &c1);
    printf("Enter rows and columns of second matrix: ");
    scanf("%d %d", &r2, &c2);

    if(c1 != r2) {
        printf("Matrix multiplication not possible!\n");
        return 1;
    }

    printf("Enter elements of first matrix:\n");
    for(int i = 0; i < r1; i++)
        for(int j = 0; j < c1; j++)
            scanf("%d", &a[i][j]);

    printf("Enter elements of second matrix:\n");
    for(int i = 0; i < r2; i++)
        for(int j = 0; j < c2; j++)
            scanf("%d", &b[i][j]);

    // Multiplication
    for(int i = 0; i < r1; i++)
        for(int j = 0; j < c2; j++)
            for(int k = 0; k < c1; k++)
                product[i][j] += a[i][k] * b[k][j];

    printf("Product matrix:\n");
    for(int i = 0; i < r1; i++) {
        for(int j = 0; j < c2; j++)
            printf("%d ", product[i][j]);
        printf("\n");
    }
    return 0;
}
```

```c
#include <stdio.h>

int sumOfDigits(int n) {
    if(n == 0) return 0;
    return (n % 10) + sumOfDigits(n / 10);
}

int main() {
    int num;
    printf("Enter a positive integer: ");
    scanf("%d", &num);
    printf("Sum of digits = %d\n", sumOfDigits(num));
    return 0;
}
```

```c
#include <stdio.h>
#include <string.h>

int main() {
    char str[200], result[200];
    int seen[256] = {0};
    int j = 0;

    printf("Enter a string: ");
    fgets(str, sizeof(str), stdin);
    str[strcspn(str, "\n")] = '\0';

    for(int i = 0; str[i] != '\0'; i++) {
        unsigned char ch = str[i];
        if(!seen[ch]) {
            seen[ch] = 1;
            result[j++] = str[i];
        }
    }
    result[j] = '\0';

    printf("String after removing duplicates: %s\n", result);
    return 0;
}
```

```c
#include <stdio.h>
#include <string.h>
#include <stdbool.h>

#define MAX_BOOKS 100

typedef struct {
    int id;
    char title[100];
    char author[100];
    int quantity;
} Book;

Book library[MAX_BOOKS];
int bookCount = 0;

void addBook() {
    if(bookCount >= MAX_BOOKS) {
        printf("Library is full!\n");
        return;
    }
    Book b;
    printf("Enter Book ID: ");
    scanf("%d", &b.id);
    // Check for duplicate ID
    for(int i = 0; i < bookCount; i++) {
        if(library[i].id == b.id) {
            printf("Book with this ID already exists!\n");
            return;
        }
    }
    printf("Enter Title: ");
    scanf(" %[^\n]", b.title);
    printf("Enter Author: ");
    scanf(" %[^\n]", b.author);
    printf("Enter Quantity: ");
    scanf("%d", &b.quantity);
    library[bookCount++] = b;
    printf("Book added successfully!\n");
}

void displayBooks() {
    if(bookCount == 0) {
        printf("No books in library.\n");
        return;
    }
    printf("\n%-10s %-30s %-20s %-10s\n", "ID", "Title", "Author", "Quantity");
    printf("---------------------------------------------------------------\n");
    for(int i = 0; i < bookCount; i++) {
        printf("%-10d %-30s %-20s %-10d\n", 
               library[i].id, library[i].title, library[i].author, library[i].quantity);
    }
}

int findBookIndex(int id) {
    for(int i = 0; i < bookCount; i++) {
        if(library[i].id == id) return i;
    }
    return -1;
}

void searchBook() {
    int id;
    printf("Enter Book ID to search: ");
    scanf("%d", &id);
    int idx = findBookIndex(id);
    if(idx == -1) {
        printf("Book not found!\n");
        return;
    }
    printf("\nBook Found:\n");
    printf("ID: %d\nTitle: %s\nAuthor: %s\nQuantity: %d\n",
           library[idx].id, library[idx].title, library[idx].author, library[idx].quantity);
}

void issueBook() {
    int id;
    printf("Enter Book ID to issue: ");
    scanf("%d", &id);
    int idx = findBookIndex(id);
    if(idx == -1) {
        printf("Book not found!\n");
        return;
    }
    if(library[idx].quantity <= 0) {
        printf("Sorry, this book is out of stock!\n");
        return;
    }
    library[idx].quantity--;
    printf("Book issued successfully! Remaining quantity: %d\n", library[idx].quantity);
}

void returnBook() {
    int id;
    printf("Enter Book ID to return: ");
    scanf("%d", &id);
    int idx = findBookIndex(id);
    if(idx == -1) {
        printf("Book not found!\n");
        return;
    }
    library[idx].quantity++;
    printf("Book returned successfully! New quantity: %d\n", library[idx].quantity);
}

int main() {
    int choice;
    do {
        printf("\n======= LIBRARY MANAGEMENT SYSTEM =======\n");
        printf("1. Add Book\n");
        printf("2. Display All Books\n");
        printf("3. Search Book by ID\n");
        printf("4. Issue Book\n");
        printf("5. Return Book\n");
        printf("6. Exit\n");
        printf("Enter your choice: ");
        scanf("%d", &choice);

        switch(choice) {
            case 1: addBook(); break;
            case 2: displayBooks(); break;
            case 3: searchBook(); break;
            case 4: issueBook(); break;
            case 5: returnBook(); break;
            case 6: printf("Exiting...\n"); break;
            default: printf("Invalid choice!\n");
        }
    } while(choice != 6);
    return 0;
}
```
